import{_ as a,o as t,c as n,a6 as s}from"./chunks/framework.DtxWasON.js";const u=JSON.parse('{"title":"3-Node Docker DevNet","description":"","frontmatter":{},"headers":[],"relativePath":"mainchain/networks/devnet/local-devnet-docker.md","filePath":"mainchain/networks/devnet/local-devnet-docker.md"}'),i={name:"mainchain/networks/devnet/local-devnet-docker.md"};function o(d,e,l,c,r,h){return t(),n("div",null,[...e[0]||(e[0]=[s('<h1 id="_3-node-docker-devnet" tabindex="-1">3-Node Docker DevNet <a class="header-anchor" href="#_3-node-docker-devnet" aria-label="Permalink to &quot;3-Node Docker DevNet&quot;">​</a></h1><div class="warning custom-block"><p class="custom-block-title">IMPORTANT</p><p>Whenever you use <code>und</code> to send Txs or query the chain ensure you pass the correct data to the <code>--chain-id</code> and if necessary <code>--node=</code> flags so that you connect to the correct network!</p></div><p>The repository contains a ready to deploy Docker composition for local development and testing. The Docker composition will spin up a DevNet using the current checked out branch&#39;s code to build and run the <code>und</code> binaries.</p><h4 id="contents" tabindex="-1">Contents <a class="header-anchor" href="#contents" aria-label="Permalink to &quot;Contents&quot;">​</a></h4><nav class="table-of-contents"><ul><li><a href="#getting-devnet">Getting DevNet</a></li><li><a href="#spinning-up-devnet">Spinning up DevNet</a></li><li><a href="#devnet-chain-id">DevNet Chain ID</a></li><li><a href="#devnet-rpc-nodes">DevNet RPC Nodes</a></li><li><a href="#devnet-docker-containers">DevNet Docker containers</a></li><li><a href="#devnet-test-accounts-wallets-and-keys">DevNet test accounts, wallets and keys</a><ul><li><a href="#importing-the-devnet-keys">Importing the DevNet keys</a></li><li><a href="#useful-devnet-defaults-for-und">Useful DevNet Defaults for und</a></li><li><a href="#rest-api-endpoints">REST API Endpoints</a></li></ul></li></ul></nav><h2 id="getting-devnet" tabindex="-1">Getting DevNet <a class="header-anchor" href="#getting-devnet" aria-label="Permalink to &quot;Getting DevNet&quot;">​</a></h2><p>Check out the <code>mainchain</code> repository:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clone</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/unification-com/mainchain</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mainchain</span></span></code></pre></div><h2 id="spinning-up-devnet" tabindex="-1">Spinning up DevNet <a class="header-anchor" href="#spinning-up-devnet" aria-label="Permalink to &quot;Spinning up DevNet&quot;">​</a></h2><p>DevNet can be started by using the <code>make</code> target:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">make</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> devnet</span></span></code></pre></div><p>To bring DevNet down cleanly, use <kbd>Ctrl</kbd>+<kbd>C</kbd>, followed by:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">make</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> devnet-down</span></span></code></pre></div><h2 id="devnet-chain-id" tabindex="-1">DevNet Chain ID <a class="header-anchor" href="#devnet-chain-id" aria-label="Permalink to &quot;DevNet Chain ID&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">IMPORTANT</p><p>DevNet&#39;s Chain ID is <code>FUND-DevNet-2</code>. Any <code>und</code> commands intended for DevNet should use the flag <code>--chain-id FUND-DevNet-2</code></p></div><h2 id="devnet-rpc-nodes" tabindex="-1">DevNet RPC Nodes <a class="header-anchor" href="#devnet-rpc-nodes" aria-label="Permalink to &quot;DevNet RPC Nodes&quot;">​</a></h2><p>By default <code>und</code> will attempt to broadcast transactions to tcp://localhost:26656. However, any of the DevNet nodes can be used to send transactions via <code>und</code> using the <code>--node=</code> flag, for example:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">und</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> query</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> TX_HASH</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --chain-id</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> FUND-DevNet-2</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --node=tcp://172.25.0.3:26661</span></span></code></pre></div><p>See below for each node&#39;s RPC IPs and Ports.</p><h2 id="devnet-docker-containers" tabindex="-1">DevNet Docker containers <a class="header-anchor" href="#devnet-docker-containers" aria-label="Permalink to &quot;DevNet Docker containers&quot;">​</a></h2><p>The DevNet composition will spin up three full validator nodes and a proxy server in the following Docker containers:</p><ul><li><code>dn_node1</code> - Full validation node, RPC on 172.25.0.3:26661, P2P on 172.25.0.3:26651</li><li><code>dn_node2</code> - Full validation node, RPC on 172.25.0.4:26662, P2P on 172.25.0.4:26652</li><li><code>dn_node3</code> - Full validation node, RPC on 172.25.0.5:26663, P2P on 172.25.0.5:26653</li><li><code>proxy</code> - a small proxy server allowing CORS queries to the <code>dn_node1</code> REST API via 172.25.0.7:1318</li></ul><p>The RPC interface is available via <code>dn_node1</code> on port <code>26661</code>, and non-CORS REST on port <code>1317</code></p><div class="tip custom-block"><p class="custom-block-title">NOTE</p><p>The DevNet nodes:<br> P2P ports set to 26651, 26652 and 26653 respectively, and not the default 26656.<br> RPC ports set to 26661, 26662 and 26663 respectively, and not the default 26657.</p></div><h2 id="devnet-test-accounts-wallets-and-keys" tabindex="-1">DevNet test accounts, wallets and keys <a class="header-anchor" href="#devnet-test-accounts-wallets-and-keys" aria-label="Permalink to &quot;DevNet test accounts, wallets and keys&quot;">​</a></h2><p>DevNet is deployed with a pre-defined <a href="https://raw.githubusercontent.com/unification-com/mainchain/master/Docker/assets/node1/config/genesis.json" target="_blank" rel="noreferrer">genesis.json</a>, containing several test accounts loaded with FUND and pre-defined validators with self delegation.</p><p>See <a href="https://github.com/unification-com/mainchain/blob/master/Docker/README.md" target="_blank" rel="noreferrer">https://github.com/unification-com/mainchain/blob/master/Docker/README.md</a> for the mnemonic phrases and keys used by the above nodes, and for test accounts included in DevNet&#39;s genesis.</p><h3 id="importing-the-devnet-keys" tabindex="-1">Importing the DevNet keys <a class="header-anchor" href="#importing-the-devnet-keys" aria-label="Permalink to &quot;Importing the DevNet keys&quot;">​</a></h3><p>The DevNet accounts can be imported as follows. First, build the <code>und</code> and <code>und</code> binaries:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">make</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span></span></code></pre></div><p>Then, for each account run the following command:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./build/und</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> keys</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> devnet_node1</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --recover</span></span></code></pre></div><p>You will be prompted to enter the mnemonic phrase, and a password for your OS&#39;s keyring. Change <code>devnet_node1</code> to an appropriate moniker for each imported account.</p><h3 id="useful-devnet-defaults-for-und" tabindex="-1">Useful DevNet Defaults for <code>und</code> <a class="header-anchor" href="#useful-devnet-defaults-for-und" aria-label="Permalink to &quot;Useful DevNet Defaults for `und`&quot;">​</a></h3><p><code>und</code> defaults for DevNet can be set as follows. This will set the corresponding values in <code>$HOME/.und_mainchain/config/client.toml</code></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>und config chain-id FUND-DevNet-2</span></span>\n<span class="line"><span>und config node tcp://localhost:26661</span></span></code></pre></div><h3 id="rest-api-endpoints" tabindex="-1">REST API Endpoints <a class="header-anchor" href="#rest-api-endpoints" aria-label="Permalink to &quot;REST API Endpoints&quot;">​</a></h3><p>With DevNet up, the REST API endpoints can be seen via <a href="http://localhost:1317/swagger/" target="_blank" rel="noreferrer">http://localhost:1317/swagger/</a></p><h4 id="next" tabindex="-1">Next <a class="header-anchor" href="#next" aria-label="Permalink to &quot;Next&quot;">​</a></h4><p>Creating and importing <a href="./accounts-wallets.html">accounts and wallets</a>, <a href="./transactions.html">sending transactions</a></p>',40)])])}const k=a(i,[["render",o]]);export{u as __pageData,k as default};
